<table class="table table-bordered" style="font-size: 12px; width: 100%; border-collapse: collapse;">
  <thead>
    <tr>
      <th style="width: 4%; text-align: center;">#</th>
      <th style="width: 32%;">Test Parameters</th>
      <th style="width: 32%;">Specification</th>
      <th style="width: 32%;">Observation</th>
    </tr>
  </thead>
  <tbody>
    {# Group readings by parameter_group #}
    {% set grouped = {} %}
    {% for row in doc.readings %}
      {% set group = row.parameter_group or "__ungrouped__" %}
      {% if not grouped[group] %}
        {% set _ = grouped.update({group: []}) %}
      {% endif %}
      {% set _ = grouped[group].append(row) %}
    {% endfor %}

    {# Render grouped data #}
    {% for group_name, rows in grouped.items() %}
      {% if group_name != "__ungrouped__" %}
        <tr>
          <td style="text-align: center;">{{ ns.serial }}</td>
          <td><strong>{{ group_name }}</strong></td>
          <td></td>
          <td></td>
        </tr>
        {% for row in rows %}
        <tr>
          <td></td>
          <td>{{ row.specification or "" }}</td>
          <td>{{ row.value or "" }}</td>
          <td>
            {% if row.numeric and row.reading_1 %}
              {{ row.reading_1 }}
            {% elif row.reading_value %}
              {{ row.reading_value }}
            {% endif %}
          </td>
        </tr>
        {% endfor %}
        {% set ns.serial = ns.serial + 1 %}
      {% else %}
        {% for row in rows %}
        <tr>
          <td style="text-align: center;">{{ ns.serial }}</td>
          <td>{{ row.specification or "" }}</td>
          <td>{{ row.value or "" }}</td>
          <td>
            {% if row.numeric and row.reading_1 %}
              {{ row.reading_1 }}
            {% elif row.reading_value %}
              {{ row.reading_value }}
            {% endif %}
          </td>
        </tr>
        {% set ns.serial = ns.serial + 1 %}
        {% endfor %}
      {% endif %}
    {% endfor %}

    {# Additional Row with Nested Table for Assay #}
    {% if doc.custom_label_claim_items %}
    <tr>
      <td style="text-align: center;">{{ ns.serial }}</td>
      <td colspan="3" style="padding: 0 !important; margin: 0 !important;">
        <table style="font-size: 12px; width: 100%; border-collapse: collapse !important; border-spacing: 0 !important; margin: 0 !important;">
          <tbody>
            <tr>
              <td style="width: 32%; padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                <strong>Assay: {{ doc.custom_claim_type or '' }}</strong>
              </td>
              <td style="width: 16%; padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                <strong>Label Claim</strong>
              </td>
              <td style="width: 16%; padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                <strong>Limit</strong>
              </td>
              <td style="width: 16%; padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                <strong>Claim Obtained</strong>
              </td>
              <td style="width: 16%; padding: 4px; border-bottom: 1px solid #ddd;">
                <strong>Result (%)</strong>
              </td>
            </tr>
            {% for item in doc.custom_label_claim_items %}
            <tr>
              <td style="padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                {{ item.contains or "" }}
              </td>
              <td style="padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                {{ item.label_claim or "" }} {{ item.label_claim_uom or "" }}
              </td>
              <td style="padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                {{ item.limit or "" }}
              </td>
              <td style="padding: 4px; border-bottom: 1px solid #ddd; border-right: 1px solid #ddd;">
                {{ item.claim_obtained or "" }} {{ item.claim_obtained_uom or "" }}
              </td>
              <td style="padding: 4px; border-bottom: 1px solid #ddd;">
                {{ "{:.2f}".format(item.result__in__) if item.result__in__ is not none else "" }}%
              </td>
            </tr>
            {% endfor %}
          </tbody>
        </table>
      </td>
    </tr>
    {% endif %}
